   125	unsigned short checksum(unsigned short *ptr, int length) {
   126	  int sum = 0;
   127	  u_short answer = 0;
   128	  unsigned short *w = ptr;
   129	  int nleft = length;
   130	
   131	  while(nleft > 1) {
   132	    sum += *w++;
   133	    nleft -= 2;
   134	  }
   135	
   136	  sum = (sum >> 16) + (sum & 0xFFFF);
   137	  sum += (sum >> 16);
   138	  answer = ~sum;
   139	  return(answer);
   140	}
