   142	/* Write an individual PDU (PCAP packet header + mac-context + mac-pdu) */
   143	static int PCAP_WritePDU(const uint8_t *PDU,
   144	                                 unsigned int length) {
   145	  pcaprec_hdr_t packet_header;
   146	  // IPv4 header
   147	  typedef struct ip_hdr {
   148	    unsigned char  ip_verlen;        // 4-bit IPv4 version 4-bit header length (in 32-bit words)
   149	    unsigned char  ip_tos;           // IP type of service
   150	    unsigned short ip_totallength;   // Total length
   151	    unsigned short ip_id;            // Unique identifier
   152	    unsigned short ip_offset;        // Fragment offset field
   153	    unsigned char  ip_ttl;           // Time to live
   154	    unsigned char  ip_protocol;      // Protocol(TCP,UDP etc)
   155	    unsigned short ip_checksum;      // IP checksum
   156	    unsigned int   ip_srcaddr;       // Source address
   157	    unsigned int   ip_destaddr;      // Source address
   158	  } IPV4_HDR;
   159	  // Define the UDP header
   160	  typedef struct udp_hdr {
   161	    unsigned short src_portno;       // Source port no.
   162	    unsigned short dst_portno;       // Dest. port no.
   163	    unsigned short udp_length;       // Udp packet length
   164	    unsigned short udp_checksum;     // Udp checksum (optional)
   165	  } UDP_HDR;
   166	  IPV4_HDR IPheader= {0};
   167	  IPheader.ip_verlen = (4 << 4) | (sizeof(IPV4_HDR) / sizeof(uint32_t));
   168	  IPheader.ip_totallength = htons(sizeof(IPV4_HDR) + sizeof(UDP_HDR) + length);
   169	  IPheader.ip_ttl    = 8;    // Time-to-live is eight
   170	  IPheader.ip_protocol = IPPROTO_UDP;
   171	  IPheader.ip_srcaddr  = inet_addr(in_ip);
   172	  IPheader.ip_destaddr = inet_addr(in_ip);
   173	  IPheader.ip_checksum = checksum((unsigned short *)&IPheader, sizeof(IPV4_HDR));
   174	  // Initialize the UDP header
   175	  UDP_HDR UDPheader;
   176	  UDPheader.src_portno = htons( PACKET_MAC_LTE_DEFAULT_UDP_PORT);
   177	  UDPheader.dst_portno = htons( PACKET_MAC_LTE_DEFAULT_UDP_PORT);
   178	  UDPheader.udp_length = htons(sizeof(UDP_HDR) + length);
   179	  UDPheader.udp_checksum = 0;
   180	  /****************************************************************/
   181	  /* PCAP Header                                                  */
   182	  /* TODO: Timestamp might want to be relative to a more sensible
   183	     base time... */
   184	  struct timeval tv;
   185	  gettimeofday(&tv, NULL);
   186	  packet_header.ts_sec = tv.tv_sec;
   187	  packet_header.ts_usec = tv.tv_usec;
   188	  packet_header.incl_len =sizeof(IPV4_HDR) + sizeof(UDP_HDR) + length;
   189	  packet_header.orig_len =sizeof(IPV4_HDR) + sizeof(UDP_HDR) + length;
   190	  /***************************************************************/
   191	  /* Now write everything to the file                            */
   192	  fwrite(&packet_header, sizeof(pcaprec_hdr_t), 1, file_fd);
   193	  fwrite(&IPheader, sizeof(IPV4_HDR), 1, file_fd);
   194	  fwrite(&UDPheader, sizeof(UDP_HDR), 1, file_fd);
   195	  fwrite(PDU, 1, length, file_fd);
   196	  fflush(file_fd);
   197	  return length;
   198	}
